DarkRPUI=DarkRPUI or {}; DarkRPUI.Scoreboard=DarkRPUI.Scoreboard or {}; function DarkRPUI.Scoreboard.BuildRankEditor(parent) parent:Clear(); DarkRPUI.UI.SectionTitle(parent,"RANK EFFECTS","None, solid, gradient, rainbow, and pulse previews."); local grid=vgui.Create("DIconLayout",parent); grid:Dock(FILL); for id,r in pairs(DarkRPUI.Scoreboard.Ranks or {}) do local card=DarkRPUI.UI.MakeAnimatedCard(grid,r.displayName or id,"Effect: "..(r.effect or "None").."\nSave-ready rank style"); card:SetSize(240,100) end end
